public int[] zeroMax(int[] nums) {
    int maxOdd = Integer.MIN_VALUE;
    boolean oddFound = false;
    for (int i = nums.length - 1; i >= 0; i--) {
        if (nums[i] % 2 != 0) {
            maxOdd = Math.max(maxOdd, nums[i]);
            oddFound = true;
        }
        if (nums[i] == 0 && oddFound) {
            nums[i] = maxOdd;
            oddFound = false;
        }
    }
    return nums;
}

