public boolean twoTwo(int[] nums) {
  Map<Integer, Integer> map = new HashMap<>();
  for (int num : nums) {
    map.put(num, map.getOrDefault(num, 0) + 1);
  }
  return map.getOrDefault(2, 0) == 0 || map.getOrDefault(2, 0) % 2 == 0;
}

